var e=JSON.parse(`[{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"관리국의 개들이 빠져나가지 못하게 막아라!","JPN":"管理局の犬たちが抜け出さないよう食い止めろ！","ENG":"Stop the Administration's dogs from escaping!","TWN":"別讓管理局的走狗逃出去！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"투항 없이 포위망을 벗어나려 하면 사살해도 상관없다!","JPN":"投降せず包囲網を抜けようとした場合、射殺しても構わない！","ENG":"Kill them if they try to escape the perimeter without surrendering!","TWN":"如果在不投降的情況下脫離包圍圈，允許射殺！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"으아, 질리지도 않나. 밀어낼 만하면 계속 늘어나잖아.","JPN":"うああ、どんどん増えてくるよ。","ENG":"Ugh, it just doesn't end. When I think I have a chance to push through, more just keep coming.","TWN":"呃啊，真是沒完沒了……剛趕走一些，又冒出來一堆。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"카운터 몇 명 잡겠다고 기갑부대까지 끌고 온단 말이야?","JPN":"カウンター数人相手に機甲部隊まで連れてくる必要ある？","ENG":"They even brought armored units to catch a few Counters?","TWN":"為了抓幾個制裁者，竟然出動了裝甲部隊？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"무인기와 전차는 이쪽에서 맡지.","JPN":"無人機と戦車はこちらが相手しよう。","ENG":"I'll handle the drones and tanks.","TWN":"我會對付無人機和坦克。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"돌격부대는 제가 밀어낼 테니, 브레히트 양은 관리자님의 엄호를 부탁드립니다.","JPN":"突撃部隊は私が追い払うので、ブレヒトさんは最高管理者様の援護をお願いします。","ENG":"I'll push back the assault force. Miss Brecht, you should protect the Administrator.","TWN":"突擊部隊由我來擊退，布萊希特請掩護好管理員。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"맡겨주세요.","JPN":"任せてください。","ENG":"Leave it to me.","TWN":"……交給我吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"너희는 뭐지? 지원을 요청한 적은 없을 텐데?","JPN":"君たちは何だ？　支援要請を送った覚えはないぞ。","ENG":"What are you doing here? I never requested for backup.","TWN":"你們是什麼人？我可沒請求支援？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"아티팩트 회수 작전을 도와 반드시 성공시키라는 이바노프 장관님의 지시가 있었습니다.","JPN":"アーティファクト回収作戦を手伝い、必ず成功させろというイワノフ長官からの指示です。","ENG":"There were orders from Minister Ivanov for us to help with the operation and secure the Artifacts.","TWN":"伊萬諾夫部長指示我們協助回收神器的行動，務必確保成功。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"아울러 관리국 인물들은 반드시 생포하라고 하시더군요.","JPN":"更に、管理局の人間は全員生け捕りにするようにと。","ENG":"He also urged to capture all Administration personnel alive.","TWN":"另外，他還說不到萬不得已，管理局的人務必要活捉。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우물로부터 클리파 에너지 신호를 포착했네.","JPN":"井戸からクリファエネルギーを捕捉した。","ENG":"I've picked up a Qlipha energy signal from the Well.","TWN":"我從井中捕捉到了逆卡巴拉能量訊號。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좌표를 확보했으니, 낚싯대를 연결할 수 있을 거야.","JPN":"座標を確保したから、釣り竿を繋げられるはずだ。","ENG":"Now that we have the coordinates, we can connect the Fishing Rod.","TWN":"已經確定座標，可以連接釣魚竿了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"정말인가요? 다행이다.","JPN":"本当ですか？　よかった。","ENG":"Really? That's good news.","TWN":"真的嗎？太好了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 죄수가 무사히 일을 처리한 모양이군요.","JPN":"あの囚人、無事やり遂げたみたいですね。","ENG":"It seems that the prisoner got the job done.","TWN":"那個囚犯似乎順利完成了任務。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 좌표 일대의 공간은… 침식파 때문에 극도로 불안정하군.","JPN":"だが、この座標一帯の空間は……侵食波のせいで極度に不安定になっている。","ENG":"But the space around the coordinates is... extremely unstable due to the Corruption ray.","TWN":"但這個座標一帶的空間……因為侵蝕波而極度不穩定。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식파가 약한 지점에 낚싯대를 연결해 탈출을 유도할 테니, 조금만 시간을 더 벌어주게.","JPN":"侵食波が弱い地点に釣り竿を繋ぎ、脱出を誘導する。もう少し時間を稼いでくれ。","ENG":"I'll connect the Fishing Rod to a point where the Corruption ray is weak to prompt an escape, so give me a little more time.","TWN":"我會在侵蝕波較弱的地方引導她撤離，請再爭取一點時間。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헉… 헉…","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"따라잡히겠어.","JPN":"追いつかれてしまう。","ENG":"It's going to catch up to me.","TWN":"要、要被追上了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"잠깐이라도 좋아… 움직임을 묶을 수만 있다면…!","JPN":"少しだけでいい……動きを止めさえできれば……！","ENG":"Even if it's just for a second... if I can stop it from moving...!","TWN":"哪怕只有一會下也好……只要能讓它停下來……！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"내 능력을… 금새 풀어버렸어.","JPN":"私の能力を……すぐに解いちゃった。","ENG":"It broke free... so easily.","TWN":"施加的束縛……很快就掙脫了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"역시… 같은 능력을 쓰기 때문인 거구나.","JPN":"やっぱり……同じ能力を使うからだよね。","ENG":"I guess... it's because she used to use the same ability.","TWN":"果然……是因為相同的能力。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};